'use client';

import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Search, PlusCircle } from 'lucide-react';
import { useState } from "react";
import { DailyDiscountsForm } from "@/components/admin/marketing/DailyDiscountsForm";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import { Label } from "@/components/ui/label";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";

type Coupon = {
  id: string;
  code: string;
  description: string;
  discount: string;
  status: 'active' | 'inactive';
};

export default function MarketingPage() {
  const [activeTab, setActiveTab] = useState('coupons');
  const [couponTab, setCouponTab] = useState('active');
  const [searchTerm, setSearchTerm] = useState('');
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const [newCoupon, setNewCoupon] = useState({
    code: '',
    description: '',
    discountType: 'percentage',
    discountValue: '',
    status: 'active'
  });

  const handleTabChange = (value: string) => {
    setActiveTab(value);
  };

  const [coupons, setCoupons] = useState<Coupon[]>([
    { id: '1', code: 'WELCOME10', description: 'New users', discount: '10%', status: 'active' },
    { id: '2', code: 'SAVE5', description: 'Fixed off', discount: '$5.00', status: 'active' },
    { id: '3', code: 'OLD50', description: 'Expired campaign', discount: '50%', status: 'inactive' },
  ]);

  const filteredCoupons = coupons.filter(coupon => {
    const matchesSearch = coupon.code.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         coupon.description.toLowerCase().includes(searchTerm.toLowerCase());
    return coupon.status === couponTab && matchesSearch;
  });

  const handleAddCoupon = () => {
    const discount = newCoupon.discountType === 'percentage' 
      ? `${newCoupon.discountValue}%` 
      : `$${newCoupon.discountValue}`;
    
    const coupon: Coupon = {
      id: String(coupons.length + 1),
      code: newCoupon.code,
      description: newCoupon.description,
      discount: discount,
      status: newCoupon.status as 'active' | 'inactive'
    };
    
    setCoupons([...coupons, coupon]);
    setIsDialogOpen(false);
    setNewCoupon({
      code: '',
      description: '',
      discountType: 'percentage',
      discountValue: '',
      status: 'active'
    });
  };

  return (
    <div className="space-y-6">
      <Tabs value={activeTab} onValueChange={handleTabChange} className="space-y-4">
        <TabsList>
          <TabsTrigger value="coupons">Coupons</TabsTrigger>
          <TabsTrigger value="daily-discounts">Daily Discounts</TabsTrigger>
          <TabsTrigger value="gift-cards">Gift Cards</TabsTrigger>
        </TabsList>
        
        <TabsContent value="coupons">
          <Card>
            <CardHeader className="pb-3">
              <div className="flex justify-between items-start">
                <div>
                  <CardTitle>Coupons</CardTitle>
                  <CardDescription>
                    Create and manage discount coupons for your customers.
                  </CardDescription>
                </div>
                <div className="flex flex-col sm:flex-row gap-3 items-end sm:items-center">
                  <div className="relative w-full sm:w-64">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                    <Input
                      placeholder="Search coupons..."
                      className="pl-9 h-10 w-full"
                      value={searchTerm}
                      onChange={(e) => setSearchTerm(e.target.value)}
                    />
                  </div>
                  <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
                    <DialogTrigger asChild>
                      <Button className="w-full sm:w-auto">
                        <PlusCircle className="h-4 w-4 mr-2" /> Add Coupon
                      </Button>
                    </DialogTrigger>
                    <DialogContent className="sm:max-w-[500px]">
                      <DialogHeader>
                        <DialogTitle>Add New Coupon</DialogTitle>
                        <DialogDescription>
                          Create a new discount coupon for your customers.
                        </DialogDescription>
                      </DialogHeader>
                      <div className="grid gap-4 py-4">
                        <div className="grid gap-2">
                          <Label htmlFor="code">Coupon Code</Label>
                          <Input
                            id="code"
                            placeholder="e.g., SAVE20"
                            value={newCoupon.code}
                            onChange={(e) => setNewCoupon({...newCoupon, code: e.target.value.toUpperCase()})}
                          />
                        </div>
                        <div className="grid gap-2">
                          <Label htmlFor="description">Description</Label>
                          <Input
                            id="description"
                            placeholder="e.g., New customer discount"
                            value={newCoupon.description}
                            onChange={(e) => setNewCoupon({...newCoupon, description: e.target.value})}
                          />
                        </div>
                        <div className="grid grid-cols-2 gap-4">
                          <div className="grid gap-2">
                            <Label htmlFor="discountType">Discount Type</Label>
                            <Select
                              value={newCoupon.discountType}
                              onValueChange={(value) => setNewCoupon({...newCoupon, discountType: value})}
                            >
                              <SelectTrigger>
                                <SelectValue />
                              </SelectTrigger>
                              <SelectContent>
                                <SelectItem value="percentage">Percentage (%)</SelectItem>
                                <SelectItem value="fixed">Fixed Amount ($)</SelectItem>
                              </SelectContent>
                            </Select>
                          </div>
                          <div className="grid gap-2">
                            <Label htmlFor="discountValue">Value</Label>
                            <Input
                              id="discountValue"
                              type="number"
                              placeholder={newCoupon.discountType === 'percentage' ? '10' : '5.00'}
                              value={newCoupon.discountValue}
                              onChange={(e) => setNewCoupon({...newCoupon, discountValue: e.target.value})}
                            />
                          </div>
                        </div>
                        <div className="grid gap-2">
                          <Label htmlFor="status">Status</Label>
                          <Select
                            value={newCoupon.status}
                            onValueChange={(value) => setNewCoupon({...newCoupon, status: value})}
                          >
                            <SelectTrigger>
                              <SelectValue />
                            </SelectTrigger>
                            <SelectContent>
                              <SelectItem value="active">Active</SelectItem>
                              <SelectItem value="inactive">Inactive</SelectItem>
                            </SelectContent>
                          </Select>
                        </div>
                      </div>
                      <div className="flex justify-end gap-3">
                        <Button variant="outline" onClick={() => setIsDialogOpen(false)}>
                          Cancel
                        </Button>
                        <Button onClick={handleAddCoupon}>
                          Add Coupon
                        </Button>
                      </div>
                    </DialogContent>
                  </Dialog>
                </div>
              </div>
            </CardHeader>
            <CardContent>
              <Tabs value={couponTab} onValueChange={setCouponTab} className="space-y-4">
                <TabsList>
                  <TabsTrigger value="active">Active coupons</TabsTrigger>
                  <TabsTrigger value="inactive">Inactive coupons</TabsTrigger>
                </TabsList>
                
                <TabsContent value="active" className="mt-0">
                  <div className="rounded-md border">
                    <Table>
                      <TableHeader>
                        <TableRow>
                          <TableHead>Code</TableHead>
                          <TableHead>Description</TableHead>
                          <TableHead>Discount</TableHead>
                        </TableRow>
                      </TableHeader>
                      <TableBody>
                        {filteredCoupons.length > 0 ? (
                          filteredCoupons.map((coupon) => (
                            <TableRow key={coupon.id}>
                              <TableCell className="font-medium">{coupon.code}</TableCell>
                              <TableCell>{coupon.description}</TableCell>
                              <TableCell>{coupon.discount}</TableCell>
                            </TableRow>
                          ))
                        ) : (
                          <TableRow>
                            <TableCell colSpan={3} className="h-24 text-center text-muted-foreground">
                              No coupons found. Create your first coupon to get started.
                            </TableCell>
                          </TableRow>
                        )}
                      </TableBody>
                    </Table>
                  </div>
                </TabsContent>
                
                <TabsContent value="inactive" className="mt-0">
                  <div className="rounded-md border">
                    <Table>
                      <TableHeader>
                        <TableRow>
                          <TableHead>Code</TableHead>
                          <TableHead>Description</TableHead>
                          <TableHead>Discount</TableHead>
                        </TableRow>
                      </TableHeader>
                      <TableBody>
                        {filteredCoupons.length > 0 ? (
                          filteredCoupons.map((coupon) => (
                            <TableRow key={coupon.id}>
                              <TableCell className="font-medium">{coupon.code}</TableCell>
                              <TableCell>{coupon.description}</TableCell>
                              <TableCell>{coupon.discount}</TableCell>
                            </TableRow>
                          ))
                        ) : (
                          <TableRow>
                            <TableCell colSpan={3} className="h-24 text-center text-muted-foreground">
                              No inactive coupons found.
                            </TableCell>
                          </TableRow>
                        )}
                      </TableBody>
                    </Table>
                  </div>
                </TabsContent>
              </Tabs>
            </CardContent>
          </Card>
        </TabsContent>
        
        <TabsContent value="daily-discounts">
          <DailyDiscountsForm />
        </TabsContent>
        
        <TabsContent value="gift-cards">
          <Card>
            <CardHeader>
              <CardTitle>Gift Cards</CardTitle>
              <CardDescription>
                Manage gift cards that customers can purchase and redeem.
              </CardDescription>
            </CardHeader>
            <CardContent>
              <div className="flex items-center justify-center h-40 rounded-lg border border-dashed">
                <p className="text-sm text-muted-foreground">Gift cards content will be displayed here</p>
              </div>
            </CardContent>
          </Card>
        </TabsContent>
      </Tabs>
    </div>
  );
}
